```javascript
/**
 * The day rate, given a rate per hour
 *
 * @param {number} ratePerHour
 * @returns {number} the rate per day
 */
export function dayRate(ratePerHour) {
  const hoursPerDay = 8;
  return ratePerHour * hoursPerDay;
}

/**
 * Calculates the number of days in a budget, rounded down
 *
 * @param {number} budget: the total budget
 * @param {number} ratePerHour: the rate per hour
 * @returns {number} the number of days
 */
export function daysInBudget(budget, ratePerHour) {
  const ratePerDay = dayRate(ratePerHour);
  return Math.floor(budget / ratePerDay);
}

/**
 * Calculates the discounted rate for large projects, rounded up
 *
 * A month is considered to be 22 working days.
 *
 * @param {number} ratePerHour
 * @param {number} numDays: number of days the project spans
 * @param {number} discount: for example 20% written as 0.2
 * @returns {number} the rounded up discounted rate
 */
export function priceWithMonthlyDiscount(ratePerHour, numDays, discount) {
  const daysPerMonth = 22;
  const fullPriceDays = numDays % daysPerMonth;
  const discountedDays = numDays - fullPriceDays;
  const discountedRate = dayRate(ratePerHour) * (1 - discount);

  const fullPriceAmount = dayRate(ratePerHour) * fullPriceDays;
  const discountedAmount = discountedRate * discountedDays;

  const totalCost = fullPriceAmount + discountedAmount;

  // Round up to the nearest whole number
  return Math.ceil(totalCost);
}
```

Here's the breakdown:
- `dayRate` takes a `ratePerHour` and returns the rate for a standard 8-hour workday.
- `daysInBudget` computes the number of whole days that can be afforded within a given `budget` using the `ratePerHour`. It rounds down to the nearest whole number of days.
- `priceWithMonthlyDiscount` calculates the total price for a project that spans multiple days, applying a discount for every full month (considered to be 22 working days). The price after applying the discount is rounded up to the nearest whole number.

